fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut prefix_sum = 0;
    let mut mod_map = std::collections::HashMap::new();
    mod_map.insert(0, -1);
    let mut sum = 0;
    let mut last = -1;

    for (i, &num) in nums.iter().enumerate() {
        prefix_sum += num;
        let mod_k = ((prefix_sum % k) + k) % k;
        if let Some(&prev) = mod_map.get(&mod_k) {
            if prev >= last {
                sum += prefix_sum - if prev >= 0 { nums[prev as usize + 1..=i].iter().sum::<i64>() } else { nums[0..=i].iter().sum::<i64>() };
                last = i as i64;
            }
        }
        mod_map.entry(mod_k).or_insert(i as i64);
    }

    nums.iter().sum::<i64>() - sum
}
